+  // The assertion below compares the VF chosen by the VPlan cost-model to the
+  // one chosen by the legacy cost-model. Differences are allowed when the
+  // VPlan contains simplifications. One missing case was loops with trivially
+  // dead, side-effect free instructions (e.g. dead loads) that VPlan drops but
+  // the legacy cost model still counts. Detect such instructions and treat
+  // them as an additional simplification to avoid false assertion failures.
+  bool HasDeadSideEffectFreeInst = false;
+  for (BasicBlock *BB : OrigLoop->getBlocks()) {
+    for (Instruction &I : *BB) {
+      if (I.use_empty()) {
+        if (isa<LoadInst>(I) || I.isBinaryOp() || isa<CastInst>(I) ||
+            isa<GetElementPtrInst>(I)) {
+          HasDeadSideEffectFreeInst = true;
+          break;
+        }
+      }
+    }
+    if (HasDeadSideEffectFreeInst)
+      break;
+  }
